local function GCDB_LibNormalize(name)
    if not name then return nil end
    name = tostring(name)
    name = string.gsub(name, '|c%x%x%x%x%x%x%x%x', '')
    name = string.gsub(name, '|r', '')
    name = string.gsub(name, '^%s+', '')
    name = string.gsub(name, '%s+$', '')
    name = string.gsub(name, '^Recipe:%s*', '')
    name = string.gsub(name, '^Formula:%s*', '')
    name = string.gsub(name, '^Plans:%s*', '')
    name = string.gsub(name, '^Pattern:%s*', '')
    name = string.gsub(name, '^Design:%s*', '')
    name = string.gsub(name, '^Schematic:%s*', '')
    return string.lower(name)
end

